  ?recipient wdt:P166 wd:Q671622 .
  ?recipient wdt:P641 wd:Q155419 .
  ?recipient wdt:P585 ?date .
  OPTIONAL { ?recipient rdfs:label ?recipientLabel . FILTER (LANG(?recipientLabel) = "en") }
